import React, { useState } from 'react';

/**
 * 带错误处理的图片组件
 * @param {Object} props 组件属性
 * @param {string} props.src 图片源URL
 * @param {string} props.alt 图片替代文本
 * @param {string} props.fallbackSrc 图片加载失败时的替代图片
 * @param {string} props.className 额外的CSS类
 * @param {Function} props.onError 图片加载错误时的回调函数
 * @returns {JSX.Element} 图片组件
 */
const ImageWithFallback = ({ 
  src, 
  alt, 
  fallbackSrc = '/images/fallback-image.svg', 
  className = '', 
  onError,
  ...rest 
}) => {
  const [error, setError] = useState(false);
  const [loaded, setLoaded] = useState(false);

  const handleError = (e) => {
    console.error(`Failed to load image: ${src}`);
    setError(true);
    
    // 阻止无限循环
    e.target.onerror = null;
    
    // 应用fallback图片
    e.target.src = fallbackSrc;
    
    // 调用外部错误处理函数
    if (onError) onError(e);
  };

  const handleLoad = () => {
    setLoaded(true);
  };

  return (
    <div className={`image-container ${!loaded && !error ? 'image-loading' : ''}`}>
      {!loaded && !error && (
        <div className="loading-placeholder">
          <svg className="animate-spin h-8 w-8 text-blue-600" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
        </div>
      )}
      <img
        src={src}
        alt={alt}
        className={`${className} ${error ? 'error-fallback' : ''}`}
        onError={handleError}
        onLoad={handleLoad}
        style={{ display: loaded || error ? 'block' : 'none' }}
        {...rest}
      />
    </div>
  );
};

export default ImageWithFallback;
